    ('54000000-0000-0000-0000-000000000105', true, current_timestamp, current_timestamp, 0, null, 'BIB-EST-D', 'Estante D - Ficcao Cientifica e Fantasia', 'Obras classicas de ficcao cientifica, fantasia e cultura nerd.', '54000000-0000-0000-0000-000000000101'),
