insert into public.item_mestre (
    id, ativo, criado_em, alterado_em, version, extra, oi, nome, descricao, observacoes, categoria_id
) values
    ('54000001-0000-0000-0000-000000000001', true, current_timestamp, current_timestamp, 0, null, 'LIV-001', 'Clean Code', 'Guia pratico para escrever codigo legivel, simples e sustentavel.', 'Titulo usado em aulas de qualidade de codigo e revisao.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000002', true, current_timestamp, current_timestamp, 0, null, 'LIV-002', 'The Pragmatic Programmer', 'Conselhos praticos para evolucao profissional e entrega de software.', 'Bom para discussoes sobre carreira e engenharia.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000003', true, current_timestamp, current_timestamp, 0, null, 'LIV-003', 'Design Patterns', 'Catalogo classico de padroes de projeto orientados a objetos.', 'Referencia para aulas de padroes.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000004', true, current_timestamp, current_timestamp, 0, null, 'LIV-004', 'Refactoring', 'Tecnicas para melhorar design de codigo existente sem alterar comportamento.', 'Apoia exercicios de melhoria incremental.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000005', true, current_timestamp, current_timestamp, 0, null, 'LIV-005', 'Domain-Driven Design', 'Fundamentos de modelagem de dominio e linguagem ubiqua.', 'Referencia para discussoes de arquitetura de negocio.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000006', true, current_timestamp, current_timestamp, 0, null, 'LIV-006', 'Code Complete', 'Manual abrangente sobre construcao profissional de software.', 'Acervo de engenharia de software.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000007', true, current_timestamp, current_timestamp, 0, null, 'LIV-007', 'Introduction to Algorithms', 'Livro classico para estudo de algoritmos e estruturas de dados.', 'Conhecido como CLRS.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000008', true, current_timestamp, current_timestamp, 0, null, 'LIV-008', 'Structure and Interpretation of Computer Programs', 'Fundamentos de computacao, abstracao e interpretadores.', 'Referencia para fundamentos de programacao.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000009', true, current_timestamp, current_timestamp, 0, null, 'LIV-009', 'Computer Networks', 'Conceitos de redes, protocolos e arquitetura da internet.', 'Usado em aulas de infraestrutura.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000010', true, current_timestamp, current_timestamp, 0, null, 'LIV-010', 'Operating System Concepts', 'Conceitos de sistemas operacionais, processos, memoria e arquivos.', 'Referencia para fundamentos de sistemas.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000011', true, current_timestamp, current_timestamp, 0, null, 'LIV-011', 'Artificial Intelligence: A Modern Approach', 'Introducao abrangente a inteligencia artificial moderna.', 'Referencia de IA para acervo tecnico.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000012', true, current_timestamp, current_timestamp, 0, null, 'LIV-012', 'The Mythical Man-Month', 'Ensaios classicos sobre gestao e complexidade em projetos de software.', 'Apoia debates de planejamento e times.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000013', true, current_timestamp, current_timestamp, 0, null, 'LIV-013', 'Peopleware', 'Livro sobre produtividade, ambiente de trabalho e equipes de software.', 'Acervo de cultura e gestao.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000014', true, current_timestamp, current_timestamp, 0, null, 'LIV-014', 'The Phoenix Project', 'Narrativa sobre fluxo, operacoes e transformacao DevOps.', 'Usado para demonstracoes de processos e gargalos.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000015', true, current_timestamp, current_timestamp, 0, null, 'LIV-015', 'The DevOps Handbook', 'Praticas para entrega continua, operacoes e melhoria organizacional.', 'Complementa aulas de DevOps.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000016', true, current_timestamp, current_timestamp, 0, null, 'LIV-016', 'The Linux Programming Interface', 'Referencia detalhada para programacao de sistemas em Linux.', 'Acervo tecnico avancado.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000017', true, current_timestamp, current_timestamp, 0, null, 'LIV-017', 'Compilers: Principles, Techniques, and Tools', 'Livro classico sobre compiladores, conhecido como Dragon Book.', 'Referencia para linguagens e compiladores.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000018', true, current_timestamp, current_timestamp, 0, null, 'LIV-018', 'Godel, Escher, Bach', 'Exploracao de logica, mente, musica e sistemas formais.', 'Obra para discussoes interdisciplinares.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000019', true, current_timestamp, current_timestamp, 0, null, 'LIV-019', 'The Art of Computer Programming', 'Serie classica sobre algoritmos e fundamentos da computacao.', 'Referencia historica de computacao.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000020', true, current_timestamp, current_timestamp, 0, null, 'LIV-020', 'Head First Design Patterns', 'Introducao visual e pratica a padroes de projeto.', 'Bom para aulas introdutorias.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000021', true, current_timestamp, current_timestamp, 0, null, 'LIV-021', 'The Lord of the Rings', 'Fantasia epica classica em um universo rico e detalhado.', 'Acervo nerd para demonstracoes variadas.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000022', true, current_timestamp, current_timestamp, 0, null, 'LIV-022', 'The Hobbit', 'Aventura de fantasia no universo da Terra-media.', 'Acervo de fantasia.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000023', true, current_timestamp, current_timestamp, 0, null, 'LIV-023', 'Dune', 'Ficcao cientifica epica sobre politica, ecologia e poder.', 'Acervo de ficcao cientifica.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000024', true, current_timestamp, current_timestamp, 0, null, 'LIV-024', 'Foundation', 'Saga classica sobre psico-historia e queda de imperios galacticos.', 'Acervo de ficcao cientifica classica.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000025', true, current_timestamp, current_timestamp, 0, null, 'LIV-025', 'Neuromancer', 'Marco do cyberpunk, inteligencia artificial e ciberespaco.', 'Acervo de cultura hacker e ficcao.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000026', true, current_timestamp, current_timestamp, 0, null, 'LIV-026', 'Snow Crash', 'Ficcao cyberpunk sobre metaverso, linguagens e cultura digital.', 'Acervo para debates sobre tecnologia e sociedade.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000027', true, current_timestamp, current_timestamp, 0, null, 'LIV-027', 'The Hitchhiker''s Guide to the Galaxy', 'Aventura espacial satirica e classica da cultura nerd.', 'Acervo leve para demonstracoes de busca e listagem.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000028', true, current_timestamp, current_timestamp, 0, null, 'LIV-028', 'Ready Player One', 'Aventura pop sobre jogos, nostalgia e realidade virtual.', 'Acervo de cultura geek contemporanea.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000029', true, current_timestamp, current_timestamp, 0, null, 'LIV-029', 'The Silmarillion', 'Mitologia e historias antigas da Terra-media.', 'Acervo de fantasia para demonstracoes.', '54000000-0000-0000-0000-000000000001'),
    ('54000001-0000-0000-0000-000000000030', true, current_timestamp, current_timestamp, 0, null, 'LIV-030', 'The Name of the Wind', 'Fantasia sobre musica, conhecimento e formacao de um heroi.', 'Acervo de fantasia contemporanea.', '54000000-0000-0000-0000-000000000001');

